// See LICENSE.Berkeley for license details.

#include <arpa/inet.h>
#include <errno.h>
#include <fcntl.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>

#include <assert.h>
#include <stdio.h>
#include <stdlib.h>

#include "remote_bitbang.h"

int rbs_init(uint16_t port)
{
    socket_fd  = 0;
    client_fd  = 0;
    recv_start = 0;
    recv_end   = 0;
    rbs_err    = 0;

    socket_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (socket_fd == -1) {
        fprintf(stderr, "remote_bitbang failed to make socket: %s (%d)\n",
                strerror(errno), errno);
        abort();
    }

    fcntl(socket_fd, F_SETFL, O_NONBLOCK);
    int reuseaddr = 1;
    if (setsockopt(socket_fd, SOL_SOCKET, SO_REUSEADDR, &reuseaddr,
                   sizeof(int)) == -1) {
        fprintf(stderr, "remote_bitbang failed setsockopt: %s (%d)\n",
                strerror(errno), errno);
        abort();
    }

    struct sockaddr_in addr;
    memset(&addr, 0, sizeof(addr));
    addr.sin_family      = AF_INET;
    addr.sin_addr.s_addr = INADDR_ANY;
    addr.sin_port        = htons(port);

    if (bind(socket_fd, (struct sockaddr *)&addr, sizeof(addr)) == -1) {
        fprintf(stderr, "remote_bitbang failed to bind socket: %s (%d)\n",
                strerror(errno), errno);
        abort();
    }

    if (listen(socket_fd, 1) == -1) {
        fprintf(stderr, "remote_bitbang failed to listen on socket: %s (%d)\n",
                strerror(errno), errno);
        abort();
    }

    socklen_t addrlen = sizeof(addr);
    if (getsockname(socket_fd, (struct sockaddr *)&addr, &addrlen) == -1) {
        fprintf(stderr, "remote_bitbang getsockname failed: %s (%d)\n",
                strerror(errno), errno);
        abort();
    }

    tck   = 1;
    tms   = 1;
    tdi   = 1;
    trstn = 1;
    quit  = 0;

    fprintf(stderr, "JTAG remote bitbang server is ready\n");
    fprintf(stderr, "Listening on port %d\n", ntohs(addr.sin_port));
    return 1;
}

void rbs_accept()
{
    fprintf(stderr, "Attempting to accept client socket\n");
    int again = 1;
    while (again != 0) {
        client_fd = accept(socket_fd, NULL, NULL);
        if (client_fd == -1) {
            if (errno == EAGAIN) {
                // No client waiting to connect right now.
            } else {
                fprintf(stderr, "failed to accept on socket: %s (%d)\n",
                        strerror(errno), errno);
                again = 0;
                abort();
            }
        } else {
            fcntl(client_fd, F_SETFL, O_NONBLOCK);
            fprintf(stderr, "Accepted successfully.");
            again = 0;
        }
    }
}

void rbs_tick(unsigned char *jtag_tck, unsigned char *jtag_tms,
              unsigned char *jtag_tdi, unsigned char *jtag_trstn,
              unsigned char jtag_tdo)
{
    if (client_fd > 0) {
        tdo = jtag_tdo;
        rbs_execute_command();
    } else {
        rbs_accept();
    }

    *jtag_tck   = tck;
    *jtag_tms   = tms;
    *jtag_tdi   = tdi;
    *jtag_trstn = trstn;
}

void rbs_reset()
{
    // trstn = 0;
}

void rbs_set_pins(char _tck, char _tms, char _tdi)
{
    tck = _tck;
    tms = _tms;
    tdi = _tdi;
}

void rbs_execute_command()
{
    char command;
    int again = 1;
    while (again) {
        ssize_t num_read = read(client_fd, &command, sizeof(command));
        if (num_read == -1) {
            if (errno == EAGAIN) {
                // We'll try again the next call.
                if (VERBOSE)
                    fprintf(
                        stderr,
                        "Received no command. Will try again on the next call\n");
            } else {
                fprintf(stderr,
                        "remote_bitbang failed to read on socket: %s (%d)\n",
                        strerror(errno), errno);
                again = 0;
                abort();
            }
        } else if (num_read == 0) {
            fprintf(stderr, "No command received. Stopping further reads.\n");
            // again = 1;
            return;
        } else {
            again = 0;
        }
    }

    int dosend = 0;

    char tosend = '?';

    switch (command) {
    case 'B':
        if (VERBOSE)
            fprintf(stderr, "*BLINK*\n");
        break;
    case 'b':
        if (VERBOSE)
            fprintf(stderr, "blink off\n");
        break;
    case 'r':
        if (VERBOSE)
            fprintf(stderr, "r-reset\n");
        rbs_reset();
        break; // This is wrong. 'r' has other bits that indicated TRST and
               // SRST.
    case 's':
        if (VERBOSE)
            fprintf(stderr, "s-reset\n");
        rbs_reset();
        break; // This is wrong.
    case 't':
        if (VERBOSE)
            fprintf(stderr, "t-reset\n");
        rbs_reset();
        break; // This is wrong.
    case 'u':
        if (VERBOSE)
            fprintf(stderr, "u-reset\n");
        rbs_reset();
        break; // This is wrong.
    case '0':
        if (VERBOSE)
            fprintf(stderr, "Write 0 0 0\n");
        rbs_set_pins(0, 0, 0);
        break;
    case '1':
        if (VERBOSE)
            fprintf(stderr, "Write 0 0 1\n");
        rbs_set_pins(0, 0, 1);
        break;
    case '2':
        if (VERBOSE)
            fprintf(stderr, "Write 0 1 0\n");
        rbs_set_pins(0, 1, 0);
        break;
    case '3':
        if (VERBOSE)
            fprintf(stderr, "Write 0 1 1\n");
        rbs_set_pins(0, 1, 1);
        break;
    case '4':
        if (VERBOSE)
            fprintf(stderr, "Write 1 0 0\n");
        rbs_set_pins(1, 0, 0);
        break;
    case '5':
        if (VERBOSE)
            fprintf(stderr, "Write 1 0 1\n");
        rbs_set_pins(1, 0, 1);
        break;
    case '6':
        if (VERBOSE)
            fprintf(stderr, "Write 1 1 0\n");
        rbs_set_pins(1, 1, 0);
        break;
    case '7':
        if (VERBOSE)
            fprintf(stderr, "Write 1 1 1\n");
        rbs_set_pins(1, 1, 1);
        break;
    case 'R':
        if (VERBOSE)
            fprintf(stderr, "Read req\n");
        dosend = 1;
        tosend = tdo ? '1' : '0';
        break;
    case 'Q':
        if (VERBOSE)
            fprintf(stderr, "Quit req\n");
        quit = 1;
        break;
    default:
        fprintf(stderr, "remote_bitbang got unsupported command '%c'\n",
                command);
    }
    if (dosend) {
        while (1) {
            ssize_t bytes = write(client_fd, &tosend, sizeof(tosend));
            if (bytes == -1) {
                fprintf(stderr, "failed to write to socket: %s (%d)\n",
                        strerror(errno), errno);
                abort();
            }
            if (bytes > 0) {
                break;
            }
        }
    }

    if (quit) {
        fprintf(stderr, "Remote end disconnected\n");
        close(client_fd);
        client_fd = 0;
    }
}

unsigned char rbs_done()
{
    return quit;
}

int rbs_exit_code()
{
    return rbs_err;
}

